{"CoRequisites": [], "CreditType": "", "Credits": "4.00", "CrossListed": "Y", "DepartmentID": "43", "Departments": "EN Applied Mathematics & Statistics", "Description": "Introduction to the basic principles of mathematical statistics and data analysis. Emphasis on techniques of application. Classical parametric estimation, hypothesis testing, and multiple decision problems; linear models, analysis of variance, and regression; nonparametric and robust procedures; decision-theoretic setting, Bayesian methods. Recommended Course Background: EN.553.620 AND ( AS.110.201 OR AS.110.212 OR EN.553.291 ).", "Equivalencies": [], "EvaluationUrls": [], "Fees": [], "GradeSystemName": "AE Grad Letter", "InstructionMethods": "In-person", "Instructors": [{"HopkinsID": "1AAB5B|1AAB5B"}], "Meetings": [{"Building": "Shaffer", "DOW": "MW", "Dates": "01-20-2026 to 04-27-2026", "Format": "Lecture", "Times": "01:30 PM - 02:45 PM"}, {"Building": "Shaffer", "DOW": "T", "Dates": "01-20-2026 to 04-27-2026", "Format": "Discussion Section", "Times": "09:00 AM - 09:50 AM"}], "PosTags": [{"Tag": "BMED-BDS"}, {"Tag": "BMED-IMD"}], "PrereqCoursesCatalogs": [{"Description": "Introduction to mathematical statistics. Finite population sampling, approximation methods,classical parametric estimation, hypothesis testing, analysis of variance, and regression. Bayesian methods.", "Name": "EN.553.430", "SssCoursesId": 39356, "StatusName": "Active", "TermName": "AE Spring 2026", "Title": "Mathematical Statistics"}, {"Description": "Probability and its applications, at the calculus level. Emphasis on techniques of application and on rigorous mathematical demonstration.  Probability, combinatorial probability, random variables, distribution functions, important probability distributions, independence, conditional probability, moments, covariance and correlation, limit theorems.  Students initiating graduate work in probability or statistics should enroll in EN.553.620 or EN.553.720.  Prerequisites: one year of calculus.  Corequisites: multivariable calculus and linear algebra.

Students who have received credit for AS.110.106 and/or AS.110.107 taken prior to Fall 2020 should contact the course instructor to determine whether they can receive permission to register for this course.", "Name": "EN.553.420", "SssCoursesId": 39352, "StatusName": "Active", "TermName": "AE Spring 2026", "Title": "Probability"}, {"Description": "Probability and its applications, at the calculus level. Emphasis on techniques of application and on rigorous mathematical demonstration. Probability, combinatorial probability, random variables, distribution functions, important probability distributions, independence, conditional probability, moments, exchangeability, joint distributions, conditional distributions and expectation, covariance and correlation, limit theorems.  The honors version of this course will have enrichment exercises that explore and extend ideas learned in the ordinary lecture.  Students initiating graduate work in probability or statistics should enroll in EN.550.620. Auditors are not permitted. Recommended Course Background: one year of calculus and mathematical maturity; Co-requisite: multivariable calculus. 
By permission of the instructor or by recommendation of an AMS faculty member.", "Name": "EN.553.421", "SssCoursesId": 44541, "StatusName": "Active", "TermName": "AE Spring 2026", "Title": "Honors Probability"}, {"Description": "Probability and its applications, at the calculus level. Emphasis on techniques of application and on rigorous mathematical demonstration. Probability, combinatorial probability, random variables, distribution functions, important probability distributions, independence, conditional probability, moments, covariance and correlation, limit theorems.  Recommended course background: (AS.110.109 or  AS.110.113) and previously or concurrently (AS.110.202 or AS.110.201 or AS.110.212).", "Name": "EN.553.620", "SssCoursesId": 39380, "StatusName": "Active", "TermName": "AE Spring 2026", "Title": "Probability"}], "Prerequisites": [{"Description": "Students may receive credit for EN.550.430/EN.553.430 or EN.553.630, but not both.", "Expression": "EN.553.430[C]", "IsNegative": "Y"}, {"Description": "Students must have completed EN.553.420 OR EN.553.421 OR EN.553.620 prior to enrolling in EN.553.630.", "Expression": "EN.553.420[C]^OR^EN.553.421[C]^OR^EN.553.620[C]", "IsNegative": "N"}], "Restrictions": [{"Description": "", "RestrictionName": "Grad students"}], "SampleSyllabus": "", "SectionCoReqNotes": "", "SectionCoRequisites": "", "StandardSyllabusLink": "", "TextbookInformations": [{"AttributeValue": "Follett", "BookstoreID": "2393", "ClassStartDate": "20260120", "CourseName": "EN.553.630", "CourseNumber": "630", "Department": "EN553", "IdrGroupTerm": "Spring 2026", "Location": "Homewood Campus", "MbsGroupDesignator": "", "MbsSiteCode": "", "Name": "01", "SectionNumber": "01", "Term": "Spring2026", "ZonesName": "ASEN - UGrad"}], "WebNotes": "Enrollment restricted to AMS Department graduate students, MSEM Operations Research students and MSEM Probability and Statistics students for two weeks. Open to graduates only after two weeks."}

{"CoRequisites": [], "CreditType": "", "Credits": "4.00", "CrossListed": "N", "DepartmentID": "43", "Departments": "EN Applied Mathematics & Statistics", "Description": "Introduction to the mathematics of finite systems. Logic; Boolean algebra; induction and recursion; sets, functions, relations, equivalence, and partially ordered sets; elementary combinatorics; modular arithmetic and the Euclidean algorithm; polynomials rings, group theory; permutations groups and Galois theory; graph theory. Selected applications. The concept of a proof and development of the ability to recognize and construct proofs and analyze algorithms are part of the course. Recommended Course Background: Four years of high school mathematics.", "Equivalencies": [], "EvaluationUrls": [], "Fees": [], "GradeSystemName": "AE Ugrad Letter", "InstructionMethods": "In-person", "Instructors": [{"HopkinsID": "ABBDCD|ABBDCD"}], "Meetings": [{"Building": "Croft Hall", "DOW": "MWF", "Dates": "01-20-2026 to 04-27-2026", "Format": "Lecture", "Times": "10:00 AM - 10:50 AM"}, {"Building": "Wyman Park", "DOW": "Th", "Dates": "01-20-2026 to 04-27-2026", "Format": "Discussion Section", "Times": "09:00 AM - 09:50 AM"}], "PosTags": [], "PrereqCoursesCatalogs": [{"Description": "Introduction to the mathematics of finite systems. Logic; Boolean algebra; induction and recursion; sets, functions, relations, equivalence, and partially ordered sets; elementary combinatorics; modular arithmetic and the Euclidean algorithm; group theory; permutations and symmetry groups; graph theory. Selected applications. The concept of a proof and development of the ability to recognize and construct proofs are part of the course. Recommended Course Background: Four years of high school mathematics.", "Name": "EN.553.171", "SssCoursesId": 39339, "StatusName": "Active", "TermName": "AE Spring 2026", "Title": "Discrete Mathematics"}, {"Description": "This course provides an introduction to mathematical reasoning and discrete structures relevant to computer science. Topics include propositional and predicate logic, proof techniques including mathematical induction, sets, relations, functions, recurrences, counting techniques, simple computational models, asymptotic analysis, discrete probability, graphs, trees, and number theory.", "Name": "EN.601.230", "SssCoursesId": 44204, "StatusName": "Active", "TermName": "AE Spring 2026", "Title": "Mathematical Foundations for Computer Science"}, {"Description": "Counting techniques: generating functions, recurrence relations, Polya’s theorem. Combinatorial designs: Latin squares, finite geometries, balanced incomplete block designs. Emphasis on problem solving. Recommended Course Background: AS.553.291 or AS.110.201

Students who have received credit for AS.110.106 and/or AS.110.107 taken prior to Fall 2020 should contact the course instructor to determine whether they can receive permission to register for this course.", "Name": "EN.553.471", "SssCoursesId": 39348, "StatusName": "Active", "TermName": "AE Spring 2026", "Title": "Combinatorial Analysis"}, {"Description": "Study of systems of “vertices” with some pairs joined by “edges.” Theory of adjacency, connectivity, traversability, feedback, and other concepts underlying properties important in engineering and the sciences. Topics include paths, cycles, and trees; routing problems associated with Euler and Hamilton; design of graphs realizing specified incidence conditions and other constraints. Attention directed toward problem solving, algorithms, and applications. One or more topics taken up in greater depth.", "Name": "EN.553.472", "SssCoursesId": 39616, "StatusName": "Active", "TermName": "AE Spring 2026", "Title": "Graph Theory"}, {"Description": "An introduction to combinatorial analysis at the graduate level. Meets concurrently with 553.471. Counting techniques: generating functions, recurrence relations, Polya’s theorem. Combinatorial designs: Latin squares, finite geometries, balanced incomplete block designs. Emphasis on problem solving. Recommended Course Background: EN.553.291 or AS.110.201", "Name": "EN.553.671", "SssCoursesId": 39789, "StatusName": "Active", "TermName": "AE Spring 2026", "Title": "Combinatorial Analysis"}, {"Description": "Study of systems of “vertices” with some pairs joined by “edges.” Theory of adjacency, connectivity, traversability, feedback, and other concepts underlying properties important in engineering and the sciences. Topics include paths, cycles, and trees; routing problems associated with Euler and Hamilton; design of graphs realizing specified incidence conditions and other constraints. Attention directed toward problem solving, algorithms, and applications. One or more topics taken up in greater depth. Recommended Course Background: (EN.553.291 OR AS.110.201 OR AS.110.212)", "Name": "EN.553.672", "SssCoursesId": 39627, "StatusName": "Active", "TermName": "AE Spring 2026", "Title": "Graph Theory"}], "Prerequisites": [{"Description": "Students may only earn credit for one of the following: EN.553.171, EN.553.172, OR EN.601.230.
EN.553.172 may not be taken after EN.553.471 OR EN.553.472 OR EN.553.671 OR EN.553.672.", "Expression": "EN.553.171[C]^OR^EN.601.230[C]^OR^EN.553.471[C]^OR^EN.553.472[C]^OR^EN.553.671[C]^OR^EN.553.672[C]", "IsNegative": "Y"}], "Restrictions": [{"Description": "", "RestrictionName": "UGrad Applied Mathematics and Statistics majors"}, {"Description": "", "RestrictionName": "Applied Mathematics and Statistics minors"}], "SampleSyllabus": "", "SectionCoReqNotes": "", "SectionCoRequisites": "", "StandardSyllabusLink": "", "TextbookInformations": [{"AttributeValue": "Follett", "BookstoreID": "2393", "ClassStartDate": "20260120", "CourseName": "EN.553.172", "CourseNumber": "172", "Department": "EN553", "IdrGroupTerm": "Spring 2026", "Location": "Homewood Campus", "MbsGroupDesignator": "", "MbsSiteCode": "", "Name": "01", "SectionNumber": "01", "Term": "Spring2026", "ZonesName": "ASEN - UGrad"}], "WebNotes": ""}

